INSERT INTO public.spells (id, name, owner_id, source, visibility, level, school, casting_time, "range", components, duration, concentration, ritual, classes, description, higher_levels, save_type, attack_type, damage_dice, damage_type, damage_at_slot_level, damage_at_char_level, heal_dice, heal_at_slot_level, area_of_effect) VALUES
('hold-person', 'Hold Person', NULL, 'srd', 'private', 2, 'Enchantment', '1 action', '60 feet', 'V, S, M (A small, straight piece of iron.)', 'Up to 1 minute', true, false, '{"Bard","Cleric","Druid","Sorcerer","Warlock","Wizard","Psion"}', 'Choose a humanoid that you can see within range. The target must succeed on a wisdom saving throw or be paralyzed for the duration. At the end of each of its turns, the target can make another wisdom saving throw. On a success, the spell ends on the target.', 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional humanoid for each slot level above 2nd. The humanoids must be within 30 feet of each other when you target them.', 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('invisibility', 'Invisibility', NULL, 'srd', 'private', 2, 'Illusion', '1 action', 'Touch', 'V, S, M (An eyelash encased in gum arabic.)', 'Up to 1 hour', true, false, '{"Bard","Sorcerer","Warlock","Wizard","Psion"}', 'A creature you touch becomes invisible until the spell ends. Anything the target is wearing or carrying is invisible as long as it is on the target''s person. The spell ends for a target that attacks or casts a spell.', 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('knock', 'Knock', NULL, 'srd', 'private', 2, 'Transmutation', '1 action', '60 feet', 'V', 'Instantaneous', false, false, '{"Bard","Sorcerer","Wizard","Psion"}', E'Choose an object that you can see within range. The object can be a door, a box, a chest, a set of manacles, a padlock, or another object that contains a mundane or magical means that prevents access.\n\nA target that is held shut by a mundane lock or that is stuck or barred becomes unlocked, unstuck, or unbarred. If the object has multiple locks, only one of them is unlocked.\n\nIf you choose a target that is held shut with arcane lock, that spell is suppressed for 10 minutes, during which time the target can be opened and shut normally.\n\nWhen you cast the spell, a loud knock, audible from as far away as 300 feet, emanates from the target object.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('lesser-restoration', 'Lesser Restoration', NULL, 'srd', 'private', 2, 'Abjuration', '1 action', 'Touch', 'V, S', 'Instantaneous', false, false, '{"Bard","Cleric","Druid","Paladin","Ranger"}', 'You touch a creature and can end either one disease or one condition afflicting it. The condition can be blinded, deafened, paralyzed, or poisoned.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('levitate', 'Levitate', NULL, 'srd', 'private', 2, 'Transmutation', '1 action', '60 feet', 'V, S, M (Either a small leather loop or a piece of golden wire bent into a cup shape with a long shank on one end.)', 'Up to 10 minutes', true, false, '{"Sorcerer","Wizard","Psion"}', E'One creature or object of your choice that you can see within range rises vertically, up to 20 feet, and remains suspended there for the duration. The spell can levitate a target that weighs up to 500 pounds. An unwilling creature that succeeds on a constitution saving throw is unaffected.\n\nThe target can move only by pushing or pulling against a fixed object or surface within reach (such as a wall or a ceiling), which allows it to move as if it were climbing. You can change the target''s altitude by up to 20 feet in either direction on your turn. If you are the target, you can move up or down as part of your move. Otherwise, you can use your action to move the target, which must remain within the spell''s range.\n\nWhen the spell ends, the target floats gently to the ground if it is still aloft.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('locate-animals-or-plants', 'Locate Animals or Plants', NULL, 'srd', 'private', 2, 'Divination', '1 action', 'Self', 'V, S, M (A bit of fur from a bloodhound.)', 'Instantaneous', false, true, '{"Bard","Druid","Ranger","Psion"}', 'Describe or name a specific kind of beast or plant. Concentrating on the voice of nature in your surroundings, you learn the direction and distance to the closest creature or plant of that kind within 5 miles, if any are present.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('locate-object', 'Locate Object', NULL, 'srd', 'private', 2, 'Divination', '1 action', 'Self', 'V, S, M (A forked twig.)', 'Up to 10 minutes', true, false, '{"Bard","Cleric","Druid","Paladin","Ranger","Wizard"}', E'Describe or name an object that is familiar to you. You sense the direction to the object''s location, as long as that object is within 1,000 feet of you. If the object is in motion, you know the direction of its movement.\n\nThe spell can locate a specific object known to you, as long as you have seen it up close--within 30 feet--at least once. Alternatively, the spell can locate the nearest object of a particular kind, such as a certain kind of apparel, jewelry, furniture, tool, or weapon.\n\nThis spell can''t locate an object if any thickness of lead, even a thin sheet, blocks a direct path between you and the object.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('magic-mouth', 'Magic Mouth', NULL, 'srd', 'private', 2, 'Illusion', '1 minute', '30 feet', 'V, S, M (A honeycomb and jade dust of at least 10 inches, the spell consumes.)', 'Until dispelled', false, true, '{"Bard","Wizard","Psion"}', E'You plant a message to an object in the range of the spell. The message is verbalized when the trigger conditions are met. Choose an object that you see, and that is not worn or carried by another creature. Then say the message, which should not exceed 25 words but listening can take up to 10 minutes. Finally, establish the circumstances that trigger the spell to deliver your message.\n\nWhen these conditions are satisfied, a magical mouth appears on the object and it articulates the message imitating your voice, the same tone used during implantation of the message. If the selected object has a mouth or something that approaches such as the mouth of a statue, the magic mouth come alive at this point, giving the illusion that the words come from the mouth of the object.\n\nWhen you cast this spell, you may decide that the spell ends when the message is delivered or it can persist and repeat the message whenever circumstances occur.\n\nThe triggering circumstance can be as general or as detailed as you like, though it must be based on visual or audible conditions that occur within 30 feet of the object. For example, you could instruct the mouth to speak when any creature moves within 30 feet of the object or when a silver bell rings within 30 feet of it.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('magic-weapon', 'Magic Weapon', NULL, 'srd', 'private', 2, 'Transmutation', '1 bonus action', 'Touch', 'V, S', 'Up to 1 hour', true, false, '{"Paladin","Wizard"}', 'You touch a nonmagical weapon. Until the spell ends, that weapon becomes a magic weapon with a +1 bonus to attack rolls and damage rolls.', 'When you cast this spell using a spell slot of 4th level or higher, the bonus increases to +2. When you use a spell slot of 6th level or higher, the bonus increases to +3.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('mirror-image', 'Mirror Image', NULL, 'srd', 'private', 2, 'Illusion', '1 action', 'Self', 'V, S', '1 minute', false, false, '{"Sorcerer","Warlock","Wizard","Psion"}', E'Three illusory duplicates of yourself appear in your space. Until the spell ends, the duplicates move with you and mimic your actions, shifting position so it''s impossible to track which image is real. You can use your action to dismiss the illusory duplicates.\n\nEach time a creature targets you with an attack during the spell''s duration, roll a d20 to determine whether the attack instead targets one of your duplicates.\n\nIf you have three duplicates, you must roll a 6 or higher to change the attack''s target to a duplicate. With two duplicates, you must roll an 8 or higher. With one duplicate, you must roll an 11 or higher.\n\nA duplicate''s AC equals 10 + your Dexterity modifier. If an attack hits a duplicate, the duplicate is destroyed. A duplicate can be destroyed only by an attack that hits it. It ignores all other damage and effects. The spell ends when all three duplicates are destroyed.\n\nA creature is unaffected by this spell if it can''t see, if it relies on senses other than sight, such as blindsight, or if it can perceive illusions as false, as with truesight.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('misty-step', 'Misty Step', NULL, 'srd', 'private', 2, 'Conjuration', '1 bonus action', 'Self', 'V', 'Instantaneous', false, false, '{"Sorcerer","Warlock","Wizard"}', 'Briefly surrounded by silvery mist, you teleport up to 30 feet to an unoccupied space that you can see.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('moonbeam', 'Moonbeam', NULL, 'srd', 'private', 2, 'Evocation', '1 action', '120 feet', 'V, S, M (Several seeds of any moonseed plant and a piece of opalescent feldspar.)', 'Up to 1 minute', true, false, '{"Druid"}', E'A silvery beam of pale light shines down in a 5-foot radius, 40-foot-high cylinder centered on a point within range. Until the spell ends, dim light fills the cylinder.\n\nWhen a creature enters the spell''s area for the first time on a turn or starts its turn there, it is engulfed in ghostly flames that cause searing pain, and it must make a constitution saving throw. It takes 2d10 radiant damage on a failed save, or half as much damage on a successful one.\n\nA shapechanger makes its saving throw with disadvantage. If it fails, it also instantly reverts to its original form and can''t assume a different form until it leaves the spell''s light.\n\nOn each of your turns after you cast this spell, you can use an action to move the beam 60 feet in any direction.', 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1dl0 for each slot level above 2nd.', 'CON', NULL, '2d10', 'Radiant', '{"2":"2d10","3":"3d10","4":"4d10","5":"5d10","6":"6d10","7":"7d10","8":"8d10","9":"9d10"}'::jsonb, NULL, NULL, NULL, '{"type":"cylinder","size":5}'::jsonb),
('pass-without-trace', 'Pass Without Trace', NULL, 'srd', 'private', 2, 'Abjuration', '1 action', 'Self', 'V, S, M (Ashes from a burned leaf of mistletoe and a sprig of spruce.)', 'Up to 1 hour', true, false, '{"Druid","Ranger"}', 'A veil of shadows and silence radiates from you, masking you and your companions from detection. For the duration, each creature you choose within 30 feet of you (including you) has a +10 bonus to Dexterity (Stealth) checks and can''t be tracked except by magical means. A creature that receives this bonus leaves behind no tracks or other traces of its passage.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('prayer-of-healing', 'Prayer of Healing', NULL, 'srd', 'private', 2, 'Evocation', '10 minutes', '30 feet', 'V', 'Instantaneous', false, false, '{"Cleric"}', 'Up to six creatures of your choice that you can see within range each regain hit points equal to 2d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', 'When you cast this spell using a spell slot of 3rd level or higher, the healing increases by 1d8 for each slot level above 2nd.', NULL, NULL, NULL, NULL, NULL, NULL, '2d8 + MOD', '{"2":"2d8 + MOD","3":"3d8 + MOD","4":"4d8 + MOD","5":"5d8 + MOD","6":"6d8 + MOD","7":"7d8 + MOD","8":"8d8 + MOD","9":"9d8 + MOD"}'::jsonb, NULL),
('protection-from-poison', 'Protection from Poison', NULL, 'srd', 'private', 2, 'Abjuration', '1 action', 'Touch', 'V, S', '1 hour', false, false, '{"Cleric","Druid","Paladin","Ranger"}', E'You touch a creature. If it is poisoned, you neutralize the poison. If more than one poison afflicts the target, you neutralize one poison that you know is present, or you neutralize one at random.\n\nFor the duration, the target has advantage on saving throws against being poisoned, and it has resistance to poison damage.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('ray-of-enfeeblement', 'Ray of Enfeeblement', NULL, 'srd', 'private', 2, 'Necromancy', '1 action', '60 feet', 'V, S', 'Up to 1 minute', true, false, '{"Warlock","Wizard"}', E'A black beam of enervating energy springs from your finger toward a creature within range. Make a ranged spell attack against the target. On a hit, the target deals only half damage with weapon attacks that use Strength until the spell ends.\n\nAt the end of each of the target''s turns, it can make a constitution saving throw against the spell. On a success, the spell ends.', NULL, 'CON', 'ranged', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('rope-trick', 'Rope Trick', NULL, 'srd', 'private', 2, 'Transmutation', '1 action', 'Touch', 'V, S, M (Powdered corn extract and a twisted loop of parchment.)', '1 hour', false, false, '{"Wizard"}', E'You touch a length of rope that is up to 60 feet long. One end of the rope then rises into the air until the whole rope hangs perpendicular to the ground. At the upper end of the rope, an invisible entrance opens to an extradimensional space that lasts until the spell ends.\n\nThe extradimensional space can be reached by climbing to the top of the rope. The space can hold as many as eight Medium or smaller creatures. The rope can be pulled into the space, making the rope disappear from view outside the space.\n\nAttacks and spells can''t cross through the entrance into or out of the extradimensional space, but those inside can see out of it as if through a 3-foot-by-5-foot window centered on the rope.\n\nAnything inside the extradimensional space drops out when the spell ends.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('scorching-ray', 'Scorching Ray', NULL, 'srd', 'private', 2, 'Evocation', '1 action', '120 feet', 'V, S', 'Instantaneous', false, false, '{"Sorcerer","Wizard"}', E'You create three rays of fire and hurl them at targets within range. You can hurl them at one target or several.\n\nMake a ranged spell attack for each ray. On a hit, the target takes 2d6 fire damage.', 'When you cast this spell using a spell slot of 3rd level or higher, you create one additional ray for each slot level above 2nd.', NULL, NULL, '2d6', 'Fire', '{"2":"2d6"}'::jsonb, NULL, NULL, NULL, NULL),
('see-invisibility', 'See Invisibility', NULL, 'srd', 'private', 2, 'Divination', '1 action', 'Self', 'V, S, M (A dash of talc and a small amount of silver powder.)', '1 hour', false, false, '{"Bard","Sorcerer","Wizard","Psion"}', 'For the duration of the spell, you see invisible creatures and objects as if they were visible, and you can see through Ethereal. The ethereal objects and creatures appear ghostly translucent.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('shatter', 'Shatter', NULL, 'srd', 'private', 2, 'Evocation', '1 action', '60 feet', 'V, S, M (A burst of mica.)', 'Instantaneous', false, false, '{"Bard","Sorcerer","Warlock","Wizard","Psion"}', E'A sudden loud ringing noise, painfully intense, erupts from a point of your choice within range. Each creature in a 10-foot-radius sphere centered on that point must make a Constitution saving throw. A creature takes 3d8 thunder damage on a failed save, or half as much damage on a successful one. A creature made of inorganic material such as stone, crystal, or metal has disadvantage on this saving throw.\n\nA non-magical item that is not worn or carried also suffers damage if it is in the area of the spell.', 'When you cast this spell using a 3 or higher level spell slot, the damage of the spell increases by 1d8 for each level of higher spell slot 2.', 'CON', NULL, '3d8', 'Thunder', '{"2":"3d8","3":"4d8","4":"5d8","5":"6d8","6":"7d8","7":"8d8","8":"9d8","9":"10d8"}'::jsonb, NULL, NULL, NULL, '{"type":"sphere","size":10}'::jsonb),
('silence', 'Silence', NULL, 'srd', 'private', 2, 'Illusion', '1 action', '120 feet', 'V, S', 'Up to 10 minutes', true, true, '{"Bard","Cleric","Ranger","Psion"}', E'For the duration, no sound can be created within or pass through a 20-foot-radius sphere centered on a point you choose within range. Any creature or object entirely inside the sphere is immune to thunder damage, and creatures are deafened while entirely inside it.\n\nCasting a spell that includes a verbal component is impossible there.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"sphere","size":20}'::jsonb),
('spider-climb', 'Spider Climb', NULL, 'srd', 'private', 2, 'Transmutation', '1 action', 'Touch', 'V, S, M (A drop of bitumen and a spider.)', 'Up to 1 hour', true, false, '{"Sorcerer","Warlock","Wizard"}', 'Until the spell ends, one willing creature you touch gains the ability to move up, down, and across vertical surfaces and upside down along ceilings, while leaving its hands free. The target also gains a climbing speed equal to its walking speed.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('spike-growth', 'Spike Growth', NULL, 'srd', 'private', 2, 'Transmutation', '1 action', '150 feet', 'V, S, M (Seven sharp thorns or seven small twigs, each sharpened to a point.)', 'Up to 10 minutes', true, false, '{"Druid","Ranger"}', E'The ground in a 20-foot radius centered on a point within range twists and sprouts hard spikes and thorns. The area becomes difficult terrain for the duration. When a creature moves into or within the area, it takes 2d4 piercing damage for every 5 feet it travels.\n\nThe transformation of the ground is camouflaged to look natural. Any creature that can''t see the area at the time the spell is cast can make a Wisdom (Perception) check against your spell save DC to recognize the terrain as hazardous before entering it.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"cylinder","size":20}'::jsonb),
('spiritual-weapon', 'Spiritual Weapon', NULL, 'srd', 'private', 2, 'Evocation', '1 bonus action', '60 feet', 'V, S', '1 minute', false, false, '{"Cleric"}', E'You create a floating, spectral weapon within range that lasts for the duration or until you cast this spell again. When you cast the spell, you can make a melee spell attack against a creature within 5 feet of the weapon. On a hit, the target takes force damage equal to 1d8 + your spellcasting ability modifier.\n\nAs a bonus action on your turn, you can move the weapon up to 20 feet and repeat the attack against a creature within 5 feet of it.\n\nThe weapon can take whatever form you choose. Clerics of deities who are associated with a particular weapon (as St. Cuthbert is known for his mace and Thor for his hammer) make this spell''s effect resemble that weapon.', 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d8 for every two slot levels above the 2nd.', NULL, 'melee', '1d8 + MOD', 'Force', '{"2":"1d8 + MOD","3":"1d8 + MOD","4":"2d8 + MOD","5":"2d8 + MOD","6":"3d8 + MOD","7":"3d8 + MOD","8":"4d8 + MOD","9":"4d8 + MOD"}'::jsonb, NULL, NULL, NULL, NULL),
('suggestion', 'Suggestion', NULL, 'srd', 'private', 2, 'Enchantment', '1 action', '30 feet', 'V, M (A snake''s tongue and either a bit of honeycomb or a drop of sweet oil.)', 'Up to 8 hours', true, false, '{"Bard","Sorcerer","Warlock","Wizard","Psion"}', E'You suggest a course of activity (limited to a sentence or two) and magically influence a creature you can see within range that can hear and understand you. Creatures that can''t be charmed are immune to this effect. The suggestion must be worded in such a manner as to make the course of action sound reasonable. Asking the creature to stab itself, throw itself onto a spear, immolate itself, or do some other obviously harmful act ends the spell.\n\nThe target must make a wisdom saving throw. On a failed save, it pursues the course of action you described to the best of its ability. The suggested course of action can continue for the entire duration. If the suggested activity can be completed in a shorter time, the spell ends when the subject finishes what it was asked to do.\n\nYou can also specify conditions that will trigger a special activity during the duration. For example, you might suggest that a knight give her warhorse to the first beggar she meets. If the condition isn''t met before the spell expires, the activity isn''t performed.\n\nIf you or any of your companions damage the target, the spell ends.', NULL, 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('warding-bond', 'Warding Bond', NULL, 'srd', 'private', 2, 'Abjuration', '1 action', 'Touch', 'V, S, M (A pair of platinum rings worth at least 50gp each, which you and the target must wear for the duration.)', '1 hour', false, false, '{"Cleric"}', E'This spell wards a willing creature you touch and creates a mystic connection between you and the target until the spell ends. While the target is within 60 feet of you, it gains a +1 bonus to AC and saving throws, and it has resistance to all damage. Also, each time it takes damage, you take the same amount of damage.\n\nThe spell ends if you drop to 0 hit points or if you and the target become separated by more than 60 feet.\n\nIt also ends if the spell is cast again on either of the connected creatures. You can also dismiss the spell as an action.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('web', 'Web', NULL, 'srd', 'private', 2, 'Conjuration', '1 action', '60 feet', 'V, S, M (A bit of spiderweb.)', 'Up to 1 hour', true, false, '{"Sorcerer","Wizard"}', E'You conjure a mass of thick, sticky webbing at a point of your choice within range. The webs fill a 20-foot cube from that point for the duration. The webs are difficult terrain and lightly obscure their area.\n\nIf the webs aren''t anchored between two solid masses (such as walls or trees) or layered across a floor, wall, or ceiling, the conjured web collapses on itself, and the spell ends at the start of your next turn. Webs layered over a flat surface have a depth of 5 feet.\n\nEach creature that starts its turn in the webs or that enters them during its turn must make a dexterity saving throw. On a failed save, the creature is restrained as long as it remains in the webs or until it breaks free.\n\nA creature restrained by the webs can use its action to make a Strength check against your spell save DC. If it succeeds, it is no longer restrained.\n\nThe webs are flammable. Any 5-foot cube of webs exposed to fire burns away in 1 round, dealing 2d4 fire damage to any creature that starts its turn in the fire.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"cube","size":20}'::jsonb),
('zone-of-truth', 'Zone of Truth', NULL, 'srd', 'private', 2, 'Enchantment', '1 action', '60 feet', 'V, S', '10 minutes', false, false, '{"Bard","Cleric","Paladin","Psion"}', E'You create a magical zone that guards against deception in a 15-foot-radius sphere centered on a point of your choice within range. Until the spell ends, a creature that enters the spell''s area for the first time on a turn or starts its turn there must make a Charisma saving throw. On a failed save, a creature can''t speak a deliberate lie while in the radius. You know whether each creature succeeds or fails on its saving throw.\n\nAn affected creature is aware of the spell and can thus avoid answering questions to which it would normally respond with a lie. Such a creature can remain evasive in its answers as long as it remains within the boundaries of the truth.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"sphere","size":15}'::jsonb),
('animate-dead', 'Animate Dead', NULL, 'srd', 'private', 3, 'Necromancy', '1 minute', '10 feet', 'V, S, M (A drop of blood, a piece of flesh, and a pinch of bone dust.)', 'Instantaneous', false, false, '{"Cleric","Wizard","Psion"}', E'This spell creates an undead servant. Choose a pile of bones or a corpse of a Medium or Small humanoid within range. Your spell imbues the target with a foul mimicry of life, raising it as an undead creature. The target becomes a skeleton if you chose bones or a zombie if you chose a corpse (the GM has the creature''s game statistics).\n\nOn each of your turns, you can use a bonus action to mentally command any creature you made with this spell if the creature is within 60 feet of you (if you control multiple creatures, you can command any or all of them at the same time, issuing the same command to each one). You decide what action the creature will take and where it will move during its next turn, or you can issue a general command, such as to guard a particular chamber or corridor. If you issue no commands, the creature only defends itself against hostile creatures. Once given an order, the creature continues to follow it until its task is complete.\n\nThe creature is under your control for 24 hours, after which it stops obeying any command you''ve given it. To maintain control of the creature for another 24 hours, you must cast this spell on the creature again before the current 24-hour period ends. This use of the spell reasserts your control over up to four creatures you have animated with this spell, rather than animating a new one.', 'When you cast this spell using a spell slot of 4th level or higher, you animate or reassert control over two additional undead creatures for each slot level above 3rd. Each of the creatures must come from a different corpse or pile of bones.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('beacon-of-hope', 'Beacon of Hope', NULL, 'srd', 'private', 3, 'Abjuration', '1 action', '30 feet', 'V, S', 'Up to 1 minute', true, false, '{"Cleric"}', 'This spell bestows hope and vitality. Choose any number of creatures within range. For the duration, each target has advantage on wisdom saving throws and death saving throws, and regains the maximum number of hit points possible from any healing.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('bestow-curse', 'Bestow Curse', NULL, 'srd', 'private', 3, 'Necromancy', '1 action', 'Touch', 'V, S', 'Up to 1 minute', true, false, '{"Bard","Cleric","Wizard","Psion"}', E'You touch a creature, and that creature must succeed on a wisdom saving throw or become cursed for the duration of the spell. When you cast this spell, choose the nature of the curse from the following options:\n\n- Choose one ability score. While cursed, the target has disadvantage on ability checks and saving throws made with that ability score.\n\n- While cursed, the target has disadvantage on attack rolls against you.\n\n- While cursed, the target must make a wisdom saving throw at the start of each of its turns. If it fails, it wastes its action that turn doing nothing.\n\n- While the target is cursed, your attacks and spells deal an extra 1d8 necrotic damage to the target.\n\nA remove curse spell ends this effect. At the GM''s option, you may choose an alternative curse effect, but it should be no more powerful than those described above. The GM has final say on such a curse''s effect.', 'If you cast this spell using a spell slot of 4th level or higher, the duration is concentration, up to 10 minutes. If you use a spell slot of 5th level or higher, the duration is 8 hours. If you use a spell slot of 7th level or higher, the duration is 24 hours. If you use a 9th level spell slot, the spell lasts until it is dispelled. Using a spell slot of 5th level or higher grants a duration that doesn''t require concentration.', 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('blink', 'Blink', NULL, 'srd', 'private', 3, 'Transmutation', '1 action', 'Self', 'V, S', '1 minute', false, false, '{"Sorcerer","Wizard"}', E'Roll a d20 at the end of each of your turns for the duration of the spell. On a roll of 11 or higher, you vanish from your current plane of existence and appear in the Ethereal Plane (the spell fails and the casting is wasted if you were already on that plane). At the start of your next turn, and when the spell ends if you are on the Ethereal Plane, you return to an unoccupied space of your choice that you can see within 10 feet of the space you vanished from. If no unoccupied space is available within that range, you appear in the nearest unoccupied space (chosen at random if more than one space is equally near). You can dismiss this spell as an action.\n\nWhile on the Ethereal Plane, you can see and hear the plane you originated from, which is cast in shades of gray, and you can''t see anything there more than 60 feet away. You can only affect and be affected by other creatures on the Ethereal Plane. Creatures that aren''t there can''t perceive you or interact with you, unless they have the ability to do so.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('call-lightning', 'Call Lightning', NULL, 'srd', 'private', 3, 'Conjuration', '1 action', '120 feet', 'V, S', 'Up to 10 minutes', true, false, '{"Druid"}', E'A storm cloud appears in the shape of a cylinder that is 10 feet tall with a 60-foot radius, centered on a point you can see 100 feet directly above you. The spell fails if you can''t see a point in the air where the storm cloud could appear (for example, if you are in a room that can''t accommodate the cloud).\n\nWhen you cast the spell, choose a point you can see within range. A bolt of lightning flashes down from the cloud to that point. Each creature within 5 feet of that point must make a dexterity saving throw. A creature takes 3d10 lightning damage on a failed save, or half as much damage on a successful one. On each of your turns until the spell ends, you can use your action to call down lightning in this way again, targeting the same point or a different one.\n\nIf you are outdoors in stormy conditions when you cast this spell, the spell gives you control over the existing storm instead of creating a new one. Under such conditions, the spell''s damage increases by 1d10.', 'When you cast this spell using a spell slot of 4th or higher level, the damage increases by 1d10 for each slot level above 3rd.', NULL, NULL, '3d10', 'Lightning', '{"3":"3d10","4":"4d10","5":"5d10","6":"6d10","7":"7d10","8":"8d10","9":"9d10"}'::jsonb, NULL, NULL, NULL, '{"type":"sphere","size":5}'::jsonb),
('clairvoyance', 'Clairvoyance', NULL, 'srd', 'private', 3, 'Divination', '10 minutes', '1 mile', 'V, S, M (A focus worth at least 100gp, either a jeweled horn for hearing or a glass eye for seeing.)', 'Up to 10 minutes', true, false, '{"Bard","Cleric","Sorcerer","Wizard","Psion"}', E'You create an invisible sensor within range in a location familiar to you (a place you have visited or seen before) or in an obvious location that is unfamiliar to you (such as behind a door, around a corner, or in a grove of trees). The sensor remains in place for the duration, and it can''t be attacked or otherwise interacted with.\n\nWhen you cast the spell, you choose seeing or hearing. You can use the chosen sense through the sensor as if you were in its space. As your action, you can switch between seeing and hearing.\n\nA creature that can see the sensor (such as a creature benefiting from see invisibility or truesight) sees a luminous, intangible orb about the size of your fist.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('conjure-animals', 'Conjure Animals', NULL, 'srd', 'private', 3, 'Conjuration', '1 action', '60 feet', 'V, S', 'Up to 1 hour', true, false, '{"Druid","Ranger"}', E'You summon fey spirits that take the form of beasts and appear in unoccupied spaces that you can see within range. Choose one of the following options for what appears:\n\n- One beast of challenge rating 2 or lower\n\n- Two beasts of challenge rating 1 or lower\n\n- Four beasts of challenge rating 1/2 or lower\n\n- Eight beasts of challenge rating 1/4 or lower\n\n- Each beast is also considered fey, and it disappears when it drops to 0 hit points or when the spell ends.\n\nThe summoned creatures are friendly to you and your companions. Roll initiative for the summoned creatures as a group, which has its own turns. They obey any verbal commands that you issue to them (no action required by you). If you don''t issue any commands to them, they defend themselves from hostile creatures, but otherwise take no actions.\n\nThe GM has the creatures'' statistics.', 'When you cast this spell using certain higher-level spell slots, you choose one of the summoning options above, and more creatures appear: twice as many with a 5th-level slot, three times as many with a 7th-level.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('counterspell', 'Counterspell', NULL, 'srd', 'private', 3, 'Abjuration', '1 reaction', '60 feet', 'S', 'Instantaneous', false, false, '{"Sorcerer","Warlock","Wizard"}', 'You attempt to interrupt a creature in the process of casting a spell. If the creature is casting a spell of 3rd level or lower, its spell fails and has no effect. If it is casting a spell of 4th level or higher, make an ability check using your spellcasting ability. The DC equals 10 + the spell''s level. On a success, the creature''s spell fails and has no effect.', 'When you cast this spell using a spell slot of 4th level or higher, the interrupted spell has no effect if its level is less than or equal to the level of the spell slot you used.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('create-food-and-water', 'Create Food and Water', NULL, 'srd', 'private', 3, 'Conjuration', '1 action', '30 feet', 'V, S', 'Instantaneous', false, false, '{"Cleric","Druid","Paladin"}', 'You create 45 pounds of food and 30 gallons of water on the ground or in containers within range, enough to sustain up to fifteen humanoids or five steeds for 24 hours. The food is bland but nourishing, and spoils if uneaten after 24 hours. The water is clean and doesn''t go bad.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('daylight', 'Daylight', NULL, 'srd', 'private', 3, 'Evocation', '1 action', '60 feet', 'V, S', '1 hour', false, false, '{"Cleric","Druid","Paladin","Ranger","Sorcerer"}', E'A 60-foot-radius sphere of light spreads out from a point you choose within range. The sphere is bright light and sheds dim light for an additional 60 feet.\n\nIf you chose a point on an object you are holding or one that isn''t being worn or carried, the light shines from the object and moves with it. Completely covering the affected object with an opaque object, such as a bowl or a helm, blocks the light.\n\nIf any of this spell''s area overlaps with an area of darkness created by a spell of 3rd level or lower, the spell that created the darkness is dispelled.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"sphere","size":60}'::jsonb),
('dispel-magic', 'Dispel Magic', NULL, 'srd', 'private', 3, 'Abjuration', '1 action', '120 feet', 'V, S', 'Instantaneous', false, false, '{"Bard","Cleric","Druid","Paladin","Sorcerer","Warlock","Wizard","Psion"}', 'Choose one creature, object, or magical effect within range. Any spell of 3rd level or lower on the target ends. For each spell of 4th level or higher on the target, make an ability check using your spellcasting ability. The DC equals 10 + the spell''s level. On a successful check, the spell ends.', 'When you cast this spell using a spell slot of 4th level or higher, you automatically end the effects of a spell on the target if the spell''s level is equal to or less than the level of the spell slot you used.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('fear', 'Fear', NULL, 'srd', 'private', 3, 'Illusion', '1 action', 'Self', 'V, S, M (A white feather or the heart of a hen.)', 'Up to 1 minute', true, false, '{"Bard","Sorcerer","Warlock","Wizard","Psion"}', E'You project a phantasmal image of a creature''s worst fears. Each creature in a 30-foot cone must succeed on a wisdom saving throw or drop whatever it is holding and become frightened for the duration.\n\nWhile frightened by this spell, a creature must take the Dash action and move away from you by the safest available route on each of its turns, unless there is nowhere to move. If the creature ends its turn in a location where it doesn''t have line of sight to you, the creature can make a wisdom saving throw. On a successful save, the spell ends for that creature.', NULL, 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"cone","size":30}'::jsonb),
('fireball', 'Fireball', NULL, 'srd', 'private', 3, 'Evocation', '1 action', '150 feet', 'V, S, M (A tiny ball of bat guano and sulfur.)', 'Instantaneous', false, false, '{"Sorcerer","Wizard"}', E'A bright streak flashes from your pointing finger to a point you choose within range and then blossoms with a low roar into an explosion of flame. Each creature in a 20-foot-radius sphere centered on that point must make a dexterity saving throw. A target takes 8d6 fire damage on a failed save, or half as much damage on a successful one.\n\nThe fire spreads around corners. It ignites flammable objects in the area that aren''t being worn or carried.', 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.', 'DEX', NULL, '8d6', 'Fire', '{"3":"8d6","4":"9d6","5":"10d6","6":"11d6","7":"12d6","8":"13d6","9":"14d6"}'::jsonb, NULL, NULL, NULL, '{"type":"sphere","size":20}'::jsonb),
('fly', 'Fly', NULL, 'srd', 'private', 3, 'Transmutation', '1 action', 'Touch', 'V, S, M (A wing feather from any bird.)', 'Up to 10 minutes', true, false, '{"Sorcerer","Warlock","Wizard","Psion"}', 'You touch a willing creature. The target gains a flying speed of 60 feet for the duration. When the spell ends, the target falls if it is still aloft, unless it can stop the fall.', 'When you cast this spell using a spell slot of 4th level or higher, you can target one additional creature for each slot level above 3rd.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('gaseous-form', 'Gaseous Form', NULL, 'srd', 'private', 3, 'Transmutation', '1 action', 'Touch', 'V, S, M (A bit of gauze and a wisp of smoke.)', 'Up to 1 hour', true, false, '{"Sorcerer","Warlock","Wizard"}', E'You transform a willing creature you touch, along with everything it''s wearing and carrying, into a misty cloud for the duration. The spell ends if the creature drops to 0 hit points. An incorporeal creature isn''t affected.\n\nWhile in this form, the target''s only method of movement is a flying speed of 10 feet. The target can enter and occupy the space of another creature. The target has resistance to nonmagical damage, and it has advantage on Strength, Dexterity, and constitution saving throws. The target can pass through small holes, narrow openings, and even mere cracks, though it treats liquids as though they were solid surfaces. The target can''t fall and remains hovering in the air even when stunned or otherwise incapacitated.\n\nWhile in the form of a misty cloud, the target can''t talk or manipulate objects, and any objects it was carrying or holding can''t be dropped, used, or otherwise interacted with. The target can''t attack or cast spells.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('glyph-of-warding', 'Glyph of Warding', NULL, 'srd', 'private', 3, 'Abjuration', '1 hour', 'Touch', 'V, S, M (Incense and powdered diamond worth at least 200 gp, which the spell consumes.)', 'Until dispelled', false, false, '{"Bard","Cleric","Wizard"}', E'When you cast this spell, you inscribe a glyph that harms other creatures, either upon a surface (such as a table or a section of floor or wall) or within an object that can be closed (such as a book, a scroll, or a treasure chest) to conceal the glyph. If you choose a surface, the glyph can cover an area of the surface no larger than 10 feet in diameter. If you choose an object, that object must remain in its place; if the object is moved more than 10 feet from where you cast this spell, the glyph is broken, and the spell ends without being triggered.\n\nThe glyph is nearly invisible and requires a successful Intelligence (Investigation) check against your spell save DC to be found.\n\nYou decide what triggers the glyph when you cast the spell. For glyphs inscribed on a surface, the most typical triggers include touching or standing on the glyph, removing another object covering the glyph, approaching within a certain distance of the glyph, or manipulating the object on which the glyph is inscribed. For glyphs inscribed within an object, the most common triggers include opening that object, approaching within a certain distance of the object, or seeing or reading the glyph. Once a glyph is triggered, this spell ends.\n\nYou can further refine the trigger so the spell activates only under certain circumstances or according to physical characteristics (such as height or weight), creature kind (for example, the ward could be set to affect aberrations or drow), or alignment. You can also set conditions for creatures that don''t trigger the glyph, such as those who say a certain password.\n\nWhen you inscribe the glyph, choose *explosive runes* or a *spell glyph*.\n\n***Explosive Runes.*** When triggered, the glyph erupts with magical energy in a 20-foot-radius sphere centered on the glyph. The sphere spreads around corners. Each creature in the area must make a Dexterity saving throw. A creature takes 5d8 acid, cold, fire, lightning, or thunder damage on a failed saving throw (your choice when you create the glyph), or half as much damage on a successful one.\n\n***Spell Glyph.*** You can store a prepared spell of 3rd level or lower in the glyph by casting it as part of creating the glyph. The spell must target a single creature or an area. The spell being stored has no immediate effect when cast in this way. When the glyph is triggered, the stored spell is cast. If the spell has a target, it targets the creature that triggered the glyph. If the spell affects an area, the area is centered on that creature. If the spell summons hostile creatures or creates harmful objects or traps, they appear as close as possible to the intruder and attack it. If the spell requires concentration, it lasts until the end of its full duration.', 'When you cast this spell using a spell slot of 4th level or higher, the damage of an explosive runes glyph increases by 1d8 for each slot level above 3rd. If you create a spell glyph, you can store any spell of up to the same level as the slot you use for the glyph of warding.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('haste', 'Haste', NULL, 'srd', 'private', 3, 'Transmutation', '1 action', '30 feet', 'V, S, M (A shaving of licorice root.)', 'Up to 1 minute', true, false, '{"Sorcerer","Wizard"}', E'Choose a willing creature that you can see within range. Until the spell ends, the target''s speed is doubled, it gains a +2 bonus to AC, it has advantage on dexterity saving throws, and it gains an additional action on each of its turns. That action can be used only to take the Attack (one weapon attack only), Dash, Disengage, Hide, or Use an Object action.\n\nWhen the spell ends, the target can''t move or take actions until after its next turn, as a wave of lethargy sweeps over it.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('hypnotic-pattern', 'Hypnotic Pattern', NULL, 'srd', 'private', 3, 'Illusion', '1 action', '120 feet', 'S, M (A glowing stick of incense or a crystal vial filled with phosphorescent material.)', 'Up to 1 minute', true, false, '{"Bard","Sorcerer","Warlock","Wizard","Psion"}', E'You create a twisting pattern of colors that weaves through the air inside a 30-foot cube within range. The pattern appears for a moment and vanishes. Each creature in the area who sees the pattern must make a wisdom saving throw. On a failed save, the creature becomes charmed for the duration. While charmed by this spell, the creature is incapacitated and has a speed of 0.\n\nThe spell ends for an affected creature if it takes any damage or if someone else uses an action to shake the creature out of its stupor.', NULL, 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('lightning-bolt', 'Lightning Bolt', NULL, 'srd', 'private', 3, 'Evocation', '1 action', 'Self', 'V, S, M (A bit of fur and a rod of amber, crystal, or glass.)', 'Instantaneous', false, false, '{"Sorcerer","Wizard"}', E'A stroke of lightning forming a line 100 feet long and 5 feet wide blasts out from you in a direction you choose. Each creature in the line must make a dexterity saving throw. A creature takes 8d6 lightning damage on a failed save, or half as much damage on a successful one.\n\nThe lightning ignites flammable objects in the area that aren''t being worn or carried.', 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.', 'DEX', NULL, '8d6', 'Lightning', '{"3":"8d6","4":"9d6","5":"10d6","6":"11d6","7":"12d6","8":"13d6","9":"14d6"}'::jsonb, NULL, NULL, NULL, '{"type":"line","size":100}'::jsonb),
('magic-circle', 'Magic Circle', NULL, 'srd', 'private', 3, 'Abjuration', '1 minute', '10 feet', 'V, S, M (Holy water or powdered silver and iron worth at least 100 gp, which the spell consumes.)', '1 hour', false, false, '{"Cleric","Paladin","Warlock","Wizard"}', E'You create a 10-foot radius, 20-foot-tall cylinder of magical energy centered on a point on the ground that you can see within range. Glowing runes appear whenever the cylinder intersects with the floor or other surface.\n\nChoose one or more of the following types of creatures: celestials, elementals, fey, fiends, or undead. The circle affects a creature of the chosen type in the following ways:\n\n- The creature can''t willingly enter the cylinder by nonmagical means. If the creature tries to use teleportation or interplanar travel to do so, it must first succeed on a charisma saving throw.\n\n- The creature has disadvantage on attack rolls against targets within the cylinder.\n\n- Targets within the cylinder can''t be charmed, frightened, or possessed by the creature.\n\nWhen you cast this spell, you can elect to cause its magic to operate in the reverse direction, preventing a creature of the specified type from leaving the cylinder and protecting targets outside it.', 'When you cast this spell using a spell slot of 4th level or higher, the duration increases by 1 hour for each slot level above 3rd.', 'CHA', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"cylinder","size":10}'::jsonb),
('major-image', 'Major Image', NULL, 'srd', 'private', 3, 'Illusion', '1 action', '120 feet', 'V, S, M (A bit of fleece.)', 'Up to 10 minutes', true, false, '{"Bard","Sorcerer","Warlock","Wizard","Psion"}', E'You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 20-foot cube. The image appears at a spot that you can see within range and lasts for the duration. It seems completely real, including sounds, smells, and temperature appropriate to the thing depicted. You can''t create sufficient heat or cold to cause damage, a sound loud enough to deal thunder damage or deafen a creature, or a smell that might sicken a creature (like a troglodyte''s stench).\n\nAs long as you are within range of the illusion, you can use your action to cause the image to move to any other spot within range. As the image changes location, you can alter its appearance so that its movements appear natural for the image. For example, if you create an image of a creature and move it, you can alter the image so that it appears to be walking. Similarly, you can cause the illusion to make different sounds at different times, even making it carry on a conversation, for example.\n\nPhysical interaction with the image reveals it to be an illusion, because things can pass through it. A creature that uses its action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image, and its other sensory qualities become faint to the creature.', 'When you cast this spell using a spell slot of 6th level or higher, the spell lasts until dispelled, without requiring your concentration.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('mass-healing-word', 'Mass Healing Word', NULL, 'srd', 'private', 3, 'Evocation', '1 bonus action', '60 feet', 'V', 'Instantaneous', false, false, '{"Cleric"}', 'As you call out words of restoration, up to six creatures of your choice that you can see within range regain hit points equal to 1d4 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', 'When you cast this spell using a spell slot of 4th level or higher, the healing increases by 1d4 for each slot level above 3rd.', NULL, NULL, NULL, NULL, NULL, NULL, '1d4 + MOD', '{"3":"1d4 + MOD","4":"2d4 + MOD","5":"3d4 + MOD","6":"4d4 + MOD","7":"5d4 + MOD","8":"6d4 + MOD","9":"7d4 + MOD"}'::jsonb, NULL)
